// Demonstration of the correct fix for the patch

#include <stdio.h>
#include <stdint.h>
#include <inttypes.h>

// Simulating APInt operations
typedef struct {
    int64_t value;
    int bits;
} APInt;

APInt sext(APInt a, int new_bits) {
    APInt result = a;
    result.bits = new_bits;
    // In real APInt, this would properly sign-extend
    return result;
}

APInt zext(APInt a, int new_bits) {
    APInt result = a;
    result.bits = new_bits;
    // Mask to zero-extend
    if (a.value < 0 && a.bits == 32) {
        result.value = (uint64_t)(uint32_t)a.value;
    }
    return result;
}

int main() {
    // Stride value: -1 (32-bit)
    APInt stride = {-1, 32};

    printf("Original stride: %" PRId64 " (32-bit)\n", stride.value);

    // What current (buggy) code does for both sext and zext:
    int64_t sext_val = stride.value;  // getSExtValue()
    printf("getSExtValue(): %" PRId64 "\n", sext_val);

    // What should be done for sext:
    APInt sext_result = sext(stride, 64);
    printf("Proper sext to 64-bit: %" PRId64 "\n", sext_result.value);

    // What should be done for zext:
    APInt zext_result = zext(stride, 64);
    printf("Proper zext to 64-bit: %" PRIu64 " (0x%016" PRIx64 ")\n", 
           (uint64_t)zext_result.value, (uint64_t)zext_result.value);

    return 0;
}
